 4→export function usePhaseFilteredFloor(floor, project, activePhaseId, phaseViewMode) {
 5→  return useMemo(
 6→    () => filterFloorByPhase(floor, project?.phases || [], activePhaseId, phaseViewMode),
 7→    [floor, project?.phases, activePhaseId, phaseViewMode]
 8→  );
 9→}
