 56→export default function SvgCanvas() {
 57→  const svgRef = useRef(null);
 58→  const isPanning = useRef(false);
 59→  const lastPanPos = useRef({ x: 0, y: 0 });
 60→  const spaceHeld = useRef(false);
 61→  const cursorPosRef = useRef({ x: 0, y: 0 });
 62→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 63→
 64→  const { project, dispatch, getFloor } = useProject();
 65→  const editor = useEditor();
 66→  const {
 67→    activeTool, selectedId, selectedType, toolState,
 68→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 69→    regionSelection, pastePreview, maximizedPanel,
 70→    activePhaseId, phaseViewMode,
 71→    dispatch: editorDispatch,
 72→  } = editor;
 73→
 74→  const floor = getFloor(activeFloorId);
 75→  const filteredFloor = usePhaseFilteredFloor(floor, project, activePhaseId, phaseViewMode);
 76→  const filteredProject = useMemo(
 77→    () => filterProjectByPhase(project, activePhaseId, phaseViewMode),
 78→    [project, activePhaseId, phaseViewMode]
 79→  );
 80→  const {
 81→    copySelection,
 82→    cutSelection,
 83→    beginPaste,
 84→    updatePastePreview,
 85→    cancelPaste,
 86→    placePaste,
 87→    previewContent,
 88→  } = usePlanClipboardController();
 89→
 90→  const tool = useEditorTool({
 91→    activeTool,
 92→    dispatch,
 93→    editorDispatch,
 94→    project,
 95→    getFloor,
 96→    activeFloorId,
 97→    viewport,
 98→    snapEnabled,
 99→    selectedId,
100→    selectedType,
101→    toolState,
102→    viewMode,
103→    activePhaseId,
104→  });
105→
106→  const getModelPos = useCallback((e) => {
107→    const rect = svgRef.current.getBoundingClientRect();
108→    return screenToModel(e.clientX, e.clientY, viewport, rect);
109→  }, [viewport]);
110→
111→  const handleMouseDown = useCallback((e) => {
112→    // Middle mouse or space+left for pan
113→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
114→      isPanning.current = true;
115→      lastPanPos.current = { x: e.clientX, y: e.clientY };
116→      e.preventDefault();
117→      return;
118→    }
119→
120→    const modelPos = getModelPos(e);
121→    if (pastePreview?.active && e.button === 0) {
122→      placePaste(modelPos);
123→      return;
124→    }
125→    tool.onMouseDown(modelPos, e);
126→  }, [getModelPos, pastePreview, placePaste, tool]);
127→
128→  const handleMouseMove = useCallback((e) => {
129→    if (isPanning.current) {
130→      const dx = e.clientX - lastPanPos.current.x;
131→      const dy = e.clientY - lastPanPos.current.y;
132→      editorDispatch({ type: 'PAN', dx, dy });
133→      lastPanPos.current = { x: e.clientX, y: e.clientY };
134→      return;
135→    }
136→
137→    const modelPos = getModelPos(e);
138→    cursorPosRef.current = modelPos;
139→    setCursorPos(modelPos);
140→    if (pastePreview?.active) {
141→      updatePastePreview(modelPos);
142→      return;
143→    }
144→    tool.onMouseMove(modelPos, e);
145→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
146→
147→  const handleMouseUp = useCallback((e) => {
148→    if (isPanning.current) {
149→      isPanning.current = false;
150→      return;
151→    }
152→    if (pastePreview?.active) return;
153→    const modelPos = getModelPos(e);
154→    tool.onMouseUp(modelPos, e);
155→  }, [getModelPos, pastePreview, tool]);
156→
157→  const handleDoubleClick = useCallback((e) => {
158→    if (pastePreview?.active) return;
159→    const modelPos = getModelPos(e);
160→    tool.onDoubleClick(modelPos, e);
161→  }, [getModelPos, pastePreview, tool]);
162→
163→  const handleWheel = useCallback((e) => {
164→    e.preventDefault();
165→    const rect = svgRef.current.getBoundingClientRect();
166→    const mouseX = e.clientX - rect.left;
167→    const mouseY = e.clientY - rect.top;
168→
169→    const direction = e.deltaY < 0 ? 1 : -1;
170→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
171→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
172→
173→    // Zoom centered on cursor
174→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
175→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
176→
177→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
178→  }, [viewport, editorDispatch]);
179→
180→  const handleResetCenterPoint = useCallback(() => {
181→    const rect = svgRef.current?.getBoundingClientRect();
182→    if (!rect) return;
183→
184→    editorDispatch({
185→      type: 'SET_VIEWPORT',
186→      viewport: {
187→        ...viewport,
188→        panX: rect.width / 2,
189→        panY: rect.height / 2,
190→      },
191→    });
192→  }, [editorDispatch, viewport]);
193→
194→  useEffect(() => {
195→    if (!statusMessage) return undefined;
196→
197→    const timer = window.setTimeout(() => {
198→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
199→    }, 2500);
200→
201→    return () => window.clearTimeout(timer);
202→  }, [statusMessage, editorDispatch]);
203→
204→  useEffect(() => {
205→    const handleKeyDown = (e) => {
206→      if (isTypingTarget(e.target)) return;
207→
208→      if (e.key === ' ') {
209→        spaceHeld.current = true;
210→        e.preventDefault();
211→      }
212→
213→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
214→        const key = e.key.toLowerCase();
215→        if (key === 'c') {
216→          e.preventDefault();
217→          copySelection();
218→          return;
219→        }
220→        if (key === 'x') {
221→          e.preventDefault();
222→          cutSelection();
223→          return;
224→        }
225→        if (key === 'v') {
226→          e.preventDefault();
227→          beginPaste(cursorPosRef.current);
228→          return;
229→        }
230→      }
231→
232→      if (e.key === 'Escape' && pastePreview?.active) {
233→        e.preventDefault();
234→        cancelPaste();
235→        return;
236→      }
237→
238→      // Tool shortcuts
239→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
240→        switch (e.key.toLowerCase()) {
241→          case 'v':
242→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
243→            return;
244→          case 'm':
245→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
246→            return;
247→          case 'w':
248→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
249→            return;
250→          case 'b':
251→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
252→            return;
253→          case 't':
254→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
255→            return;
256→          case 'q':
257→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
258→            return;
259→          case 's':
260→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
261→            return;
262→          case 'r':
263→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
264→            return;
265→          case 'd':
266→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
267→            return;
268→          case 'n':
269→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
270→            return;
271→          case 'c':
272→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
273→            return;
274→          case 'l':
275→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
276→            return;
277→          case 'h':
278→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.RAILING });
279→            return;
280→          case 'f':
281→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
282→            editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
283→            return;
284→        }
285→      }
286→
287→      tool.onKeyDown(e);
288→    };
289→
290→    const handleKeyUp = (e) => {
291→      if (isTypingTarget(e.target)) return;
292→
293→      if (e.key === ' ') {
294→        spaceHeld.current = false;
295→      }
296→    };
297→
298→    window.addEventListener('keydown', handleKeyDown);
299→    window.addEventListener('keyup', handleKeyUp);
300→    return () => {
301→      window.removeEventListener('keydown', handleKeyDown);
302→      window.removeEventListener('keyup', handleKeyUp);
303→    };
304→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
305→
306→  // Prevent default context menu on SVG
307→  useEffect(() => {
308→    const svg = svgRef.current;
309→    if (!svg) return;
310→    const prevent = (e) => e.preventDefault();
311→    svg.addEventListener('contextmenu', prevent);
312→    svg.addEventListener('wheel', handleWheel, { passive: false });
313→    return () => {
314→      svg.removeEventListener('contextmenu', prevent);
315→      svg.removeEventListener('wheel', handleWheel);
316→    };
317→  }, [handleWheel]);
318→
319→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
320→  const zoomPercent = Math.round(viewport.zoom * 1000);
321→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
322→  const isCanvasMaximized = maximizedPanel === 'canvas';
323→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
324→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
325→    : null;
326→  const selectionCount = regionSelection?.objectCount || 0;
327→  const liveWallBearing = activeTool === TOOLS.WALL && toolState.start && toolState.preview
328→    ? formatSurveyorBearing(pointsToSurveyorBearing(toolState.start, toolState.preview))
329→    : null;
330→
331→  return (
332→    <div className={styles.canvasContainer}>
333→      <CompassOverlay className={styles.compassDock} />
334→      <svg
335→        ref={svgRef}
336→        className={styles.svg}
337→        style={{ cursor }}
338→        onMouseDown={handleMouseDown}
339→        onMouseMove={handleMouseMove}
340→        onMouseUp={handleMouseUp}
341→        onDoubleClick={handleDoubleClick}
342→      >
343→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
344→          {viewMode === 'plan' && showGrid && <GridRenderer />}
345→          {viewMode === 'plan' && showGrid && (
346→            <rect
347→              x={-100000} y={-100000}
348→              width={200000} height={200000}
349→              fill="url(#grid-major)"
350→              style={{ pointerEvents: 'none' }}
351→            />
352→          )}
353→          {floor && (
354→            viewMode === 'plan' ? (
355→              <>
356→                <FixtureDefs />
357→                {(filteredFloor.slabs || []).map(slab => (
358→                  <SlabRenderer key={slab.id} slab={slab} selectedId={selectedId} />
359→                ))}
360→                <RoomRenderer rooms={filteredFloor.rooms} selectedId={selectedId} />
361→                <RoomPreview toolState={toolState} activeTool={activeTool} />
362→                <WallRenderer walls={filteredFloor.walls} columns={filteredFloor.columns || []} />
363→                <BeamRenderer beams={filteredFloor.beams || []} columns={filteredFloor.columns || []} />
364→                <StairRenderer stairs={filteredFloor.stairs || []} />
365→                <LandingRenderer landings={filteredFloor.landings || []} />
366→                <RailingRenderer railings={filteredFloor.railings || []} />
367→                <ColumnRenderer columns={filteredFloor.columns || []} />
368→                <FixtureRenderer fixtures={filteredFloor.fixtures || []} />
369→                <DoorRenderer doors={filteredFloor.doors} walls={filteredFloor.walls} />
370→                <WindowRenderer windows={filteredFloor.windows} walls={filteredFloor.walls} />
371→                {(floor.sectionCuts || []).map(sc => (
372→                  <SectionCutRenderer key={sc.id} sectionCut={sc} selectedId={selectedId} />
373→                ))}
374→                <AnnotationRenderer floor={floor} />
375→                <ClipboardPreviewLayer content={previewContent} />
376→                <RegionSelectionOverlay
377→                  marqueeBounds={marqueeBounds}
378→                  selectionBounds={regionSelection?.bounds || null}
379→                />
380→                <SelectionOverlay
381→                  selectedId={selectedId}
382→                  selectedType={selectedType}
383→                  floor={floor}
384→                  zoom={viewport.zoom}
385→                />
386→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
387→                <WallPreview toolState={toolState} activeTool={activeTool} />
388→                <SlabPreview toolState={toolState} activeTool={activeTool} />
389→                <BeamPreview
390→                  toolState={toolState}
391→                  activeTool={activeTool}
392→                  columns={floor.columns || []}
393→                  floorLevel={getFloorElevation(floor)}
394→                />
395→                <StairPreview
396→                  toolState={toolState}
397→                  activeTool={activeTool}
398→                  floorId={floor.id}
399→                />
400→                <DoorWindowPreview
401→                  toolState={toolState}
402→                  activeTool={activeTool}
403→                  walls={floor.walls}
404→                />
405→                <SectionCutPreview toolState={toolState} activeTool={activeTool} />
406→                <RailingPreview toolState={toolState} activeTool={activeTool} />
407→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
408→                <LandingPreview toolState={toolState} activeTool={activeTool} />
409→                <FixturePreview toolState={toolState} activeTool={activeTool} />
410→              </>
411→            ) : viewMode === 'section_view' ? (
412→              <SectionRenderer
413→                project={filteredProject}
414→                floor={filteredFloor}
415→                activeSectionCutId={activeSectionCutId}
416→              />
417→            ) : (
418→              <ElevationRenderer
419→                project={filteredProject}
420→                floor={filteredFloor}
421→                viewMode={viewMode}
422→                selectedId={selectedId}
423→                selectedType={selectedType}
424→              />
425→            )
426→          )}
427→        </g>
428→      </svg>
429→      <div className={styles.overlayControls}>
430→        <button
431→          type="button"
432→          className={styles.overlayBtn}
433→          onClick={handleResetCenterPoint}
434→          title="Reset center point"
435→          aria-label="Reset center point"
436→        >
437→          <CenterViewIcon />
438→        </button>
439→        <button
440→          type="button"
441→          className={styles.overlayBtn}
442→          onClick={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'canvas' })}
443→          title={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
444→          aria-label={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
445→        >
446→          {isCanvasMaximized ? <CollapseIcon /> : <ExpandIcon />}
447→        </button>
448→      </div>
449→      <div className={styles.statusBar}>
450→        <span>X: {Math.round(cursorPos.x)} mm</span>
451→        <span>Y: {Math.round(cursorPos.y)} mm</span>
452→        <span>Zoom: {zoomPercent}%</span>
453→        <span>View: {viewMode}</span>
454→        <span>Tool: {displayedTool}</span>
455→        {activePhaseId && (
456→          <span>Phase: {(project.phases || []).find(p => p.id === activePhaseId)?.name || 'Unknown'} ({phaseViewMode})</span>
457→        )}
458→        {liveWallBearing && <span>Bearing: {liveWallBearing}</span>}
459→        {selectionCount > 0 && <span>Selection: {selectionCount} objects</span>}
460→        {pastePreview?.active && <span>Paste: click to place</span>}
461→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
462→      </div>
463→    </div>
464→  );
465→}
