 65→    if (nextScope === 'all') return;
 66→    if (!orderedFloors.some((floor) => floor.id === nextScope)) return;
 67→    if (nextScope !== activeFloorId) {
 68→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: nextScope });
 69→    }
 70→  }, [activeFloorId, editorDispatch, orderedFloors]);
 71→  const handlePreviewPick = useCallback((target) => {
 72→    if (!target?.sourceId || !target?.kind) {
 73→      editorDispatch({ type: 'DESELECT' });
