 75→    }
 76→
 77→    if (target.floorId && target.floorId !== activeFloorId) {
 78→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: target.floorId });
 79→    }
 80→
 81→    editorDispatch({ type: 'SELECT_OBJECT', id: target.sourceId, objectType: target.kind });
 82→  }, [activeFloorId, editorDispatch]);
 83→
 84→  useEffect(() => {
 85→    if (!containerRef.current) return undefined;
 86→
 87→    const viewport = createPreviewViewport(containerRef.current);
 88→    viewportRef.current = viewport;
