 95→      resizeObserverRef.current = observer;
 96→    }
 97→
 98→    viewport.resize();
 99→
100→    return () => {
101→      resizeObserverRef.current?.disconnect?.();
102→      resizeObserverRef.current = null;
103→      viewport.dispose();
104→      viewportRef.current = null;
105→    };
106→  }, []);
107→
108→  useEffect(() => {
109→    viewportRef.current?.setPickHandler(handlePreviewPick);
110→  }, [handlePreviewPick]);
111→
112→  useEffect(() => {
