 50→    if (viewMode !== 'plan') {
 51→      return createReadOnlyHandler();
 52→    }
 53→
 54→    const ctx = {
 55→      dispatch, editorDispatch,
 56→      getFloor: (...args) => getFloorRef.current(...args),
 57→      activeFloorId, viewport, snapEnabled, activePhaseId,
 58→    };
