 63→      case TOOLS.WALL:
 64→        return createWallDrawHandler(ctx);
 65→      case TOOLS.BEAM:
 66→        return createBeamPlaceHandler(ctx);
 67→      case TOOLS.STAIR:
 68→        return createStairPlaceHandler(ctx);
 69→      case TOOLS.SECTION:
 70→        return createSectionPlaceHandler(ctx);
 71→      case TOOLS.SLAB:
 72→        return createSlabPlaceHandler(ctx);
 73→      case TOOLS.ROOM:
 74→        return createRoomPlaceHandler(ctx);
 75→      case TOOLS.SELECT:
 76→        return createSelectHandler(ctx);
 77→      case TOOLS.DOOR:
 78→        return createDoorPlaceHandler(ctx);
 79→      case TOOLS.WINDOW:
 80→        return createWindowPlaceHandler(ctx);
 81→      case TOOLS.COLUMN:
 82→        return createColumnPlaceHandler(ctx);
 83→      case TOOLS.LANDING:
